<!-- /wp:group -->
<!-- wp:group {"metadata":{"name":"Lore Column 1b"},"className":"founders-lore-col","layout":{"type":"default"}} -->
<div class="wp-block-group founders-lore-col">
<!-- wp:paragraph {"className":"founders-lore-text","style":{"color":{"text":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dcolor\u002d\u002dc-bone)"},"typography":{"fontFamily":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dfont-family\u002d\u002dlato)"}}} -->
<p class="has-text-color founders-lore-text" style="color:var(--wp--preset--color--c-bone);font-family:var(--wp--preset--font-family--lato)">For generations, the people of Eldermoor have whispered their names with reverence and dread in equal measure. Seraphine the Wise, whose sight pierced the veils of time. Aldric the Golden, whose blade carved order from chaos. Thornwen the Green, whose roots held the world together. And Varek the Shieldborn, whose ambition would one day crack the very foundations they had built.</p>
<!-- /wp:paragraph -->
</div>
<!-- /wp:group -->
</div>
<!-- /wp:group -->
